describe("projectImport: native field resolution", () => {
    function parseXml(dptAttr, address, name) {
        address = address || "1/0/0";
        name = name || "TestGA";
        const xmlStr = `<GroupRange Name="Main" RangeStart="0" RangeEnd="65535"><GroupAddress Name="${name}" Address="${address}" Description="test" DPTs="${dptAttr}" /></GroupRange>`;
        let result;
        projectImport.parseInput(adapter, xmlStr, (error, res) => {
            result = res;
        });
        return result[0];
    }

    function parseXmlRaw(xmlBody) {
        let result, error;
        projectImport.parseInput(adapter, xmlBody, (err, res) => {
            error = err;
            result = res;
        });
        return { result, error };
    }

    // --- Bugfix tests: native.desc, encoding, signedness ---

    it("native.desc should include subtype description (DPT9.001)", () => {
        const obj = parseXml("DPST-9-1");
        expect(obj.native.desc).to.equal("Basetype: 16-bit floating point value, Subtype: temperature");
    });

    it("native.encoding should resolve subtype.enc (DPT1.001)", () => {
        const obj = parseXml("DPST-1-1");
        expect(obj.native.encoding).to.deep.equal({ 0: "Off", 1: "On" });
    });

    it("native.force_encoding should resolve for DPT16.001", () => {
        const obj = parseXml("DPST-16-1");
        expect(obj.native.force_encoding).to.equal("ISO-8859-1");
    });

    it("native.signedness should resolve basetype.signedness (DPT8.001)", () => {
        const obj = parseXml("DPST-8-1");
        expect(obj.native.signedness).to.equal("signed");
    });

    // --- Additional DPT coverage ---

    it("DPT5.001 should have unit %, range 0-100, unsigned", () => {
        const obj = parseXml("DPST-5-1");
        expect(obj.common.type).to.equal("number");
        expect(obj.common.unit).to.equal("%");
        expect(obj.native.min).to.equal(0);
        expect(obj.native.max).to.equal(100);
        expect(obj.native.bitlength).to.equal(8);
        expect(obj.native.signedness).to.equal("unsigned");
    });

    it("DPT14.019 should be 32-bit float with unit A", () => {
        const obj = parseXml("DPST-14-19");
        expect(obj.common.type).to.equal("number");
        expect(obj.common.unit).to.equal("A");
        expect(obj.native.bitlength).to.equal(32);
        expect(obj.native.desc).to.include("Subtype:");
    });

    it("DPT232.600 (RGB) should be object type with 24 bits", () => {
        const obj = parseXml("DPST-232-600");
        expect(obj.common.type).to.equal("object");
        expect(obj.native.valuetype).to.equal("basic");
        expect(obj.native.bitlength).to.equal(24);
    });

    it("DPT10.001 (time) should be number with composite valuetype", () => {
        const obj = parseXml("DPST-10-1");
        expect(obj.common.type).to.equal("number");
        expect(obj.common.role).to.equal("date");
        expect(obj.native.valuetype).to.equal("composite");
    });

    it("DPT3.007 (dimming control) should be composite object", () => {
        const obj = parseXml("DPST-3-7");
        expect(obj.common.type).to.equal("object");
        expect(obj.native.valuetype).to.equal("composite");
        expect(obj.native.autoread).to.equal(false);
    });

    // --- Edge cases ---

    it("GA without DPTs attribute should be skipped with warning", () => {
        const xmlStr = '<GroupRange Name="Main" RangeStart="0" RangeEnd="65535"><GroupAddress Name="NoDPT" Address="1/0/0" Description="no dpt" /></GroupRange>';
        const { result, error } = parseXmlRaw(xmlStr);
        expect(result).to.have.length(0);
        expect(error).to.include("no DPT is assigned");
    });

    it("DPT without subtype should still produce valid object", () => {
        // DPT1 without subtype (base-only, e.g. "DPT-1")
        const xmlStr = '<GroupRange Name="Main" RangeStart="0" RangeEnd="65535"><GroupAddress Name="BaseOnly" Address="1/0/0" Description="base" DPTs="DPT-1" /></GroupRange>';
        const { result, error } = parseXmlRaw(xmlStr);
        expect(result).to.have.length(1);
        expect(result[0].native.dpt).to.equal("DPT1");
        expect(error).to.include("only set base DPT");
    });

    it("base-only DPT5 should get role 'value' not 'level'", () => {
        // DPT-5 without subtype resolves to DPT5.001 (%) internally,
        // but role "level" must only be assigned for explicit subtypes
        const xmlStr = '<GroupRange Name="Main" RangeStart="0" RangeEnd="65535"><GroupAddress Name="BaseDPT5" Address="1/0/0" Description="base5" DPTs="DPT-5" /></GroupRange>';
        const { result } = parseXmlRaw(xmlStr);
        expect(result[0].common.role).to.equal("value");
        expect(result[0].native.dpt).to.equal("DPT5");
    });

    it("explicit DPT5.001 should get role 'level'", () => {
        const obj = parseXml("DPST-5-1");
        expect(obj.common.role).to.equal("level");
    });

    it("multiple GAs should all be parsed", () => {
        const xmlStr = `<GroupRange Name="Main" RangeStart="0" RangeEnd="65535">
            <GroupAddress Name="GA1" Address="1/0/0" Description="a" DPTs="DPST-1-1" />
            <GroupAddress Name="GA2" Address="1/0/1" Description="b" DPTs="DPST-9-1" />
            <GroupAddress Name="GA3" Address="1/0/2" Description="c" DPTs="DPST-5-1" />
        </GroupRange>`;
        const { result } = parseXmlRaw(xmlStr);
        expect(result).to.have.length(3);
        expect(result[0].native.address).to.equal("1/0/0");
        expect(result[1].native.address).to.equal("1/0/1");
        expect(result[2].native.address).to.equal("1/0/2");
    });

    it("nested GroupRanges should build correct path", () => {
        const xmlStr = `<GroupRange Name="Beleuchtung" RangeStart="0" RangeEnd="65535">
            <GroupRange Name="EG" RangeStart="0" RangeEnd="255">
                <GroupAddress Name="Licht" Address="1/0/0" Description="test" DPTs="DPST-1-1" />
            </GroupRange>
        </GroupRange>`;
        const { result } = parseXmlRaw(xmlStr);
        expect(result).to.have.length(1);
        expect(result[0]._id).to.include("Beleuchtung");
        expect(result[0]._id).to.include("EG");
        expect(result[0]._id).to.include("Licht");
    });

    it("Description attribute should map to common.desc", () => {
        const xmlStr = '<GroupRange Name="Main" RangeStart="0" RangeEnd="65535"><GroupAddress Name="TestGA" Address="1/0/0" Description="Wohnzimmer Licht" DPTs="DPST-1-1" /></GroupRange>';
        const { result } = parseXmlRaw(xmlStr);
        expect(result[0].common.desc).to.equal("Wohnzimmer Licht");
    });

    it("DPT1.017 (trigger) should have encoding for both states", () => {
        const obj = parseXml("DPST-1-17");
        expect(obj.native.encoding).to.deep.equal({ 0: "trigger", 1: "trigger" });
        expect(obj.common.type).to.equal("boolean");
    });

    // --- DPT types from POC_KNX_XML_Source ---

    it("DPT1.008 (up/down) should have correct encoding", () => {
        const obj = parseXml("DPST-1-8");
        expect(obj.common.type).to.equal("boolean");
        expect(obj.common.states).to.deep.equal({ 0: "Up", 1: "Down" });
        expect(obj.native.encoding).to.deep.equal({ 0: "Up", 1: "Down" });
        expect(obj.native.desc).to.include("Subtype: up/down");
    });

    it("DPT1.009 (open/close) should have correct encoding", () => {
        const obj = parseXml("DPST-1-9");
        expect(obj.common.states).to.deep.equal({ 0: "Open", 1: "Close" });
        expect(obj.native.desc).to.include("Subtype: open/close");
    });

    it("DPT17.001 (scene number) should be number with autoread=false", () => {
        const obj = parseXml("DPST-17-1");
        expect(obj.common.type).to.equal("number");
        expect(obj.native.dpt).to.equal("DPT17.001");
        expect(obj.native.bitlength).to.equal(8);
        expect(obj.native.min).to.equal(0);
        expect(obj.native.max).to.equal(255);
        expect(obj.native.autoread).to.equal(false);
    });

    it("DPT5.004 (percent 0-255) should differ from DPT5.001 range", () => {
        const obj = parseXml("DPST-5-4");
        expect(obj.common.type).to.equal("number");
        expect(obj.common.unit).to.equal("%");
        expect(obj.native.min).to.equal(0);
        expect(obj.native.max).to.equal(255);
        expect(obj.native.signedness).to.equal("unsigned");
    });

    it("DPT7.001 (2-byte unsigned counter) should have correct range", () => {
        const obj = parseXml("DPST-7-1");
        expect(obj.common.type).to.equal("number");
        expect(obj.common.unit).to.equal("pulses");
        expect(obj.native.bitlength).to.equal(16);
        expect(obj.native.min).to.equal(0);
        expect(obj.native.max).to.equal(65535);
        expect(obj.native.signedness).to.equal("unsigned");
    });

    it("DPT9.004 (lux) should have unit lux", () => {
        const obj = parseXml("DPST-9-4");
        expect(obj.common.type).to.equal("number");
        expect(obj.common.unit).to.equal("lux");
        expect(obj.native.bitlength).to.equal(16);
        expect(obj.native.desc).to.include("Subtype: lux");
    });

    // --- XML format edge cases ---

    it("DatapointType attribute should work (alternative to DPTs)", () => {
        const xmlStr = '<GroupRange Name="Main" RangeStart="0" RangeEnd="65535"><GroupAddress Name="TestGA" Address="1/0/0" Description="test" DatapointType="DPST-1-1" /></GroupRange>';
        const { result } = parseXmlRaw(xmlStr);
        expect(result).to.have.length(1);
        expect(result[0].native.dpt).to.equal("DPT1.001");
        expect(result[0].common.type).to.equal("boolean");
    });

    it("Umlaute in GroupRange and GA names should be preserved", () => {
        const xmlStr = '<GroupRange Name="Belüftung" RangeStart="0" RangeEnd="65535"><GroupRange Name="Küche" RangeStart="0" RangeEnd="255"><GroupAddress Name="Lüfter Stärke" Address="1/0/0" Description="Lüfter" DPTs="DPST-5-1" /></GroupRange></GroupRange>';
        const { result } = parseXmlRaw(xmlStr);
        expect(result).to.have.length(1);
        expect(result[0].common.name).to.equal("Lüfter Stärke");
        expect(result[0].common.desc).to.equal("Lüfter");
        expect(result[0]._id).to.include("Belüftung");
        expect(result[0]._id).to.include("Küche");
    });

    // --- Duplicate GA address handling ---

    it("duplicate GA address should be skipped with warning", () => {
        const xmlStr = '<GroupRange Name="Main" RangeStart="0" RangeEnd="65535">' +
            '<GroupAddress Name="Light1" Address="1/0/0" Description="first" DPTs="DPST-1-1" />' +
            '<GroupAddress Name="Light2" Address="1/0/0" Description="duplicate" DPTs="DPST-1-1" />' +
            '</GroupRange>';
        const { result, error } = parseXmlRaw(xmlStr);
        expect(result).to.have.length(1);
        expect(result[0].common.name).to.equal("Light1");
        expect(error).to.include("duplicate address");
    });

    // --- BOM handling ---

    it("XML with BOM should be parsed correctly", () => {
        const xmlStr = '\uFEFF<GroupRange Name="Main" RangeStart="0" RangeEnd="65535"><GroupAddress Name="BomTest" Address="2/0/0" Description="bom" DPTs="DPST-9-1" /></GroupRange>';
        const { result, error } = parseXmlRaw(xmlStr);
        expect(result).to.have.length(1);
        expect(result[0].common.name).to.equal("BomTest");
    });

    // --- Empty/null XML ---

    it("empty XML string should return empty result", () => {
        const { result } = parseXmlRaw("");
        expect(result).to.be.an("array").that.is.empty;
    });

    // --- useBoolean config ---

    it("1-bit DPT with enc should be 'mixed' when useBoolean is not set", () => {
        // DPT1.001 has enc={0:"Off",1:"On"} and bitlength=1
        const obj = parseXml("DPST-1-1");
        // adapter mock has no config.useBoolean, so should be boolean (bitlength==1 path wins over enc path)
        // The code: enc path sets type="mixed", then bitlength==1 path sets type="boolean"
        expect(obj.common.type).to.equal("boolean");
    });

    it("1-bit DPT with enc and useBoolean=true should be boolean", () => {
        const savedConfig = adapter.config;
        adapter.config = { useBoolean: true };
        const obj = parseXml("DPST-1-1");
        expect(obj.common.type).to.equal("boolean");
        adapter.config = savedConfig;
    });

    // --- Unresolvable DPT (raw interface) ---

    it("completely unknown DPT should produce string type with raw desc", () => {
        const xmlStr = '<GroupRange Name="Main" RangeStart="0" RangeEnd="65535"><GroupAddress Name="RawGA" Address="3/0/0" Description="raw" DPTs="DPST-888-1" /></GroupRange>';
        const { result } = parseXmlRaw(xmlStr);
        expect(result).to.have.length(1);
        expect(result[0].common.type).to.equal("string");
        expect(result[0].native.desc).to.include("raw value");
        expect(result[0].native.bitlength).to.be.undefined;
        expect(result[0].native.valuetype).to.be.undefined;
    });

    // --- min/max absent for non-number types ---

    it("boolean DPT should not have min/max in native", () => {
        const obj = parseXml("DPST-1-1");
        expect(obj.native.min).to.be.undefined;
        expect(obj.native.max).to.be.undefined;
    });

    it("string DPT should not have min/max in native", () => {
        const obj = parseXml("DPST-16-1");
        expect(obj.native.min).to.be.undefined;
        expect(obj.native.max).to.be.undefined;
    });

    // --- Float DPT has no min/max (cleared range) ---

    it("float DPT9 should not have min/max in native", () => {
        const obj = parseXml("DPST-9-1");
        expect(obj.native.min).to.be.undefined;
        expect(obj.native.max).to.be.undefined;
    });

    // --- Trigger DPT autoread ---

    it("trigger DPT (DPT17.001) should have autoread=false", () => {
        const obj = parseXml("DPST-17-1");
        expect(obj.native.autoread).to.equal(false);
    });

    it("non-trigger DPT (DPT9.001) should have autoread=true", () => {
        const obj = parseXml("DPST-9-1");
        expect(obj.native.autoread).to.equal(true);
    });

    // --- Multiple errors in one parse ---

    it("multiple issues should concatenate error messages", () => {
        const xmlStr = '<GroupRange Name="Main" RangeStart="0" RangeEnd="65535">' +
            '<GroupAddress Name="NoDpt" Address="4/0/0" Description="none" />' +
            '<GroupAddress Name="BaseOnly" Address="4/0/1" Description="base" DPTs="DPT-5" />' +
            '</GroupRange>';
        const { error } = parseXmlRaw(xmlStr);
        expect(error).to.include("Not adding");
        expect(error).to.include("base DPT");
    });
});
